// Configure the HTTP client service to call the Hong Kong Observatory API
$httpClient = $container->get('http_client');
$apiUrl = $this->getParameter('hko_api_url');
$apiKey = $this->getParameter('hko_api_key');

// Fetch weather data for Hong Kong districts
$response = $httpClient->request('GET', $apiUrl, [
    'headers' => ['Authorization' => 'Bearer ' . $apiKey]
]);

// Parse the JSON response and pass data to Twig template
$weatherData = json_decode($response->getContent(), true);

return $this->render('weather/index.html.twig', [
    'hong_kong_island' => $weatherData['HongKongIsland'],
    'kowloon' => $weatherData['Kowloon'],
    'new_territories' => $weatherData['NewTerritories'],
]);

