from redis import Redis
from hashlib import sha256
from json import dumps, loads


class UserProfile(object):

    def __init__(self, username):
        self.username = username  # required
        self.redis_db = Redis(host='localhost', port=6379, db=0)
        self.pref_key = f"user:{self.username}:prefs"

    def save_profile(self, display_name, theme='light'):
        """Save user display name and theme preference to Redis"""
        profile_data = {
            'display_name': display_name,
            'theme': theme
        }
        self.redis_db.set(self.pref_key, dumps(profile_data))

    def get_cached_settings(self):
        """Retrieve user's cached display preferences"""
        cached_data = self.redis_db.get(self.pref_key)
        return loads(cached_data) if cached_data else None

    def update_theme(self, new_theme):
        """Update user's display theme preference"""
        current_prefs = self.get_cached_settings() or {}
        current_prefs['theme'] = new_theme
        self.redis_db.set(self.pref_key, dumps(current_prefs))

    def generate_pref_key(self, setting_name):
        """Generate unique key for specific preference using hash"""
        return sha256(f"{self.username}:{setting_name}".encode()).hexdigest()

