def brightness_lcd(level):
    # With LCD on Raspberry Pi
    if level == 'up':
        current = get_current_brightness()
        new_level = min(current + 10, 100)
        set_brightness(new_level)
    elif level == 'down':
        current = get_current_brightness()
        new_level = max(current - 10, 0)
        set_brightness(new_level)
    return get_current_brightness()

