def adjust_alsa_volume(level):
    # ALSA volume control for Raspberry Pi
    if level == 'up':
        current = get_current_volume()
        new_level = min(current + 5, 100)
        set_volume(new_level)
        return f'Volume increased to {new_level}%'
    elif level == 'down':
        current = get_current_volume()
        new_level = max(current - 5, 0)
        set_volume(new_level)
        return f'Volume decreased to {new_level}%'

