/**
 * 描述呢個 Google 日曆連接器
 * 主要功能係幫用戶自動同步日曆活動
 *
 * @author fito
 */
class connectorGoogle {
    /**
     * 初始化 Google API 客戶端
     * 設定驗證同埋預設時區（香港時間）
     */
    public function __construct() {
        $this->client = new Google_Client();
        $this->client->setAuthConfig('credentials.json');
        $this->client->addScope(Google_Service_Calendar::CALENDAR_READONLY);
        $this->client->setTimeZone('Asia/Hong_Kong');
    }

    /**
     * 獲取用戶嘅日曆活動
     * 可以指定日期範圍同埋最大數量
     *
     * @param string $startDate 開始日期（格式：YYYY-MM-DD）
     * @param string $endDate 結束日期（格式：YYYY-MM-DD）
     * @param int $maxResults 最多返回幾多個活動
     * @return array 整潔嘅活動資料
     */
    public function getCalendarEvents($startDate, $endDate, $maxResults = 10) {
        $service = new Google_Service_Calendar($this->client);
        $events = $service->events->listEvents('primary', [
            'timeMin' => $startDate . 'T00:00:00+08:00',
            'timeMax' => $endDate . 'T23:59:59+08:00',
            'maxResults' => $maxResults,
            'orderBy' => 'startTime',
            'singleEvents' => true
        ]);

        return $this->formatEvents($events);
    }

    /**
     * 將活動資料整理成簡潔嘅格式
     *
     * @param Google_Service_Calendar_Events $events 原始活動資料
     * @return array 整理後嘅活動資料
     */
    private function formatEvents($events) {
        $formatted = [];
        foreach ($events->getItems() as $event) {
            $formatted[] = [
                'summary' => $event->getSummary(),
                'start' => $event->getStart()->dateTime ?: $event->getStart()->date,
                'end' => $event->getEnd()->dateTime ?: $event->getEnd()->date,
                'location' => $event->getLocation(),
                'description' => $event->getDescription()
            ];
        }
        return $formatted;
    }
}

