            return "電郵地址缺少@符號，請檢查下啦！";
        } elseif (!checkdnsrr($domain, "MX")) {
            return "Domain '$domain' 好似唔存在，請確認下寫法啱唔啱？";
        }
        return "電郵地址格式有問題，請重新輸入！";
    }
    return "電郵地址格式正確，多謝！";

