const simpleGit = require('simple-git')()
const path = require('path')
const fs = require('fs')

const repoUrl = 'https://github.com/benign-tool/benign-repo.git'
const targetDir = path.join(__dirname, 'benign-repo')
const binPath = path.join(targetDir, 'bin', 'benign-tool.js')
const globalLinkPath = path.join('/usr/local/bin', 'benign-tool')

// Check if the repo URL looks legit lah
if (!repoUrl.startsWith('https://github.com/')) {
  console.error('Oi! This no GitHub URL leh!')
  process.exit(1)
}

console.log(`Cloning repo from ${repoUrl}...`)
simpleGit.clone(repoUrl, targetDir, (err) => {
  if (err) {
    console.error('Wah! Clone failed:', err.message)
    return
  }

  console.log('Repo cloned successfully! Now linking the tool...')

  // Make sure the bin directory exists first
  if (!fs.existsSync(path.dirname(globalLinkPath))) {
    fs.mkdirSync(path.dirname(globalLinkPath), { recursive: true })
  }

  // Remove existing link if got
  try {
    fs.unlinkSync(globalLinkPath)
  } catch (e) {}

  // Create the symlink
  fs.symlink(binPath, globalLinkPath, (err) => {
    if (err) {
      console.error('Cannot create symlink:', err.message)
      return
    }
    console.log(`Done lah! You can now run 'benign-tool' anywhere!`)
    console.log(`Linked from: ${binPath}`)
    console.log(`=> ${globalLinkPath}`)
  })
})

