  'fetch: api' + [' request', apiUrl].join(' ') + ' lah\n'
)

https.get(apiUrl, (res) => {
  if (res.statusCode !== 200) {
    process.stderr.write(`Error: Request failed with status code ${res.statusCode} leh\n`)
    return
  }

  let data = ''
  res.on('data', (chunk) => {
    data += chunk
  })

  res.on('end', () => {
    fs.writeFile(outputFile, data, (err) => {
      if (err) {
        process.stderr.write(`Error: Cannot write file lah ${err.message}\n`)
        return
      }

      process.stdout.write(`File saved: ${outputFile} wor\n`)
      process.stdout.write(` => Check the data inside wor!\n`)
    })
  })
}).on('error', (err) => {
  process.stderr.write(`Error: Request failed leh ${err.message}\n`)
})

