    try:
        return subprocess.check_output(['date', '+%Y'], text=True).strip()
    except subprocess.CalledProcessError:
        return '2023'  # 預設年份

def get_month():
    try:
        return subprocess.check_output(['date', '+%m'], text=True).strip()
    except subprocess.CalledProcessError:
        return '01'  # 預設月份

def get_day():
    try:
        return subprocess.check_output(['date', '+%d'], text=True).strip()
    except subprocess.CalledProcessError:
        return '01'  # 預設日子

