    try:
        return subprocess.check_output(['date', f'--date={days_ago} day ago', '+%Y'], text=True).strip()
    except subprocess.CalledProcessError:
        return '2023'  # 預設年份

def get_prev_month(days_ago):
    try:
        return subprocess.check_output(['date', f'--date={days_ago} day ago', '+%m'], text=True).strip()
    except subprocess.CalledProcessError:
        return '01'  # 預設月份

