function fileCallback(key) {
    return function(err, data) {
      if (err) {
        console.error(`載入文件時出錯：${err.message}`);
        return;
      }
      try {
        fileData[key] = data.toString('utf8');
      } catch (e) {
        console.error(`轉換文件數據時出錯：${e.message}`);
      }
    };
  };
  function loadFile(filePath, key) {
    fs.readFile(filePath, fileCallback(key));
    console.log(`開始載入文件：${filePath}`);
  }

