function fileCallback(key) {
    return function(err, data) {
      if (err) {
        console.error(`讀取文件 ${key} 失敗喇:`, err);
        return;
      }
      try {
        fileData[key] = JSON.parse(data);
      } catch (parseErr) {
        console.error(`解析文件 ${key} 嘅JSON有問題喎:`, parseErr);
      }
    };
  };
  function loadFile(filePath, key) {
    fs.readFile(filePath, 'utf8', fileCallback(key));
